import os
import subprocess
import json

print("RAB_DATA_DIR:", os.environ.get("RAB_DATA_DIR", "not set"))
print("/data exists:", os.path.exists("/data"))
if os.path.exists("/data"):
    print("/data contents:", os.listdir("/data"))

# Read mounts
print("\n=== /proc/mounts ===")
try:
    with open("/proc/mounts") as f:
        for line in f:
            if any(x in line for x in ["data", "assist", "experiment"]):
                print(line.strip())
except Exception as e:
    print("Error reading mounts:", e)

# Read config.json from /experiments if exists
config_path = "/experiments/config.json"
if os.path.exists(config_path):
    print("\n=== config.json ===")
    try:
        with open(config_path) as f:
            cfg = json.load(f)
            print(json.dumps(cfg, indent=2))
    except Exception as e:
        print("Error:", e)

# Read experiment.log (last 50 lines)
log_path = "/experiments/experiment.log"
if os.path.exists(log_path):
    print("\n=== experiment.log (tail) ===")
    try:
        with open(log_path) as f:
            lines = f.readlines()[-50:]
            for line in lines:
                print(line.rstrip())
    except Exception as e:
        print("Error:", e)

# Search for potential data files (not only .pt)
print("\n=== File search ===")
search_dirs = ["/", "/experiments", "/workspace", "/tmp", "/home", "/root", "/mnt", "/media", "/opt"]
for d in search_dirs:
    if not os.path.isdir(d):
        continue
    try:
        for root, dirs, files in os.walk(d, onerror=lambda e: None):
            for f in files:
                full = os.path.join(root, f)
                # look for any file that might be data
                if f.startswith("train") or f.startswith("val") or f.startswith("test") or \
                   "assist" in f.lower() or "knowledge" in f.lower() or "2009" in f:
                    size = os.path.getsize(full)
                    print(f"Potential data: {full} ({size} bytes)")
            if len(root.split(os.sep)) > 8:  # limit depth
                dirs.clear()
    except PermissionError:
        pass

print("\nDone.")
